import sys
from math import ceil
input = sys.stdin.readline

def check(h, m, n):
    h = list(h)
    for i in range(2, n):
        need = max(0, m - h[i-2])
        d = (need + 1) // 2  # ceil(need/2)
        if 3 * d > h[i]:
            return False
        h[i-2] += 2 * d
        h[i-1] += d
        h[i] -= 3 * d
    return all(x >= m for x in h)

t = int(input())
for _ in range(t):
    n = int(input())
    h = list(map(int, input().split()))
    lo, hi = 0, max(h)
    while lo < hi:
        mid = (lo + hi + 1) // 2
        if check(h, mid, n):
            lo = mid
        else:
            hi = mid - 1
    print(lo)

